-- Migration 0004 — Oria master menu / SHOPHOUSE_GIA_MENU.
-- Generated from SHOPHOUSE_GIA_MENU_FOR_WEB_with_unit.xlsx
-- 12 categories, 147 products
--
-- Strategy:
--   1. Soft-deactivate everything that's already in the DB so the UI
--      doesn't show old fruit-house demo data alongside the new master.
--   2. Upsert the 12 categories with hierarchy.
--   3. Upsert all products + create matching 0-quantity inventory rows.
--
PRAGMA foreign_keys = ON;

-- 1) Deactivate previous demo data ----------------------------------
UPDATE products   SET is_active = 0, updated_at = strftime('%s','now')*1000 WHERE id LIKE 'p-%';
UPDATE categories SET is_active = 0, updated_at = strftime('%s','now')*1000 WHERE id IN ('fresh-juice','smoothie','cut-fruit','fruit-box','combo');

